#!/usr/bin/env node

const fs = require('fs');
const path = require('path');

function generatePackageLock() {
  const packageJsonPath = path.join(process.cwd(), 'package.json');
  
  if (!fs.existsSync(packageJsonPath)) {
    console.error("Error: No package.json found in the current directory.");
    process.exit(1);
  }

  try {
    console.log("Generating package-lock.json...");
    require('child_process').execSync(`npm install`, { stdio: 'inherit' });
    console.log("package-lock.json generated successfully.");
  } catch (error) {
    console.error("Error generating package-lock.json:", error.message);
    process.exit(1);
  }
}

generatePackageLock();